class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  String? _username;
  bool _biometricEnabled = false;
  bool _isBiometricAvailable = false;
  final BiometricService _biometricService = BiometricService();

  @override
  void initState() {
    super.initState();
    _loadUserData();
  }

  Future<void> _loadUserData() async {
    final username = await AuthPreferences.getUsername();
    final biometricEnabled = await AuthPreferences.isBiometricEnabled();
    final biometricAvailable = await _biometricService.isBiometricAvailable();

    setState(() {
      _username = username;
      _biometricEnabled = biometricEnabled;
      _isBiometricAvailable = biometricAvailable;
    });
  }

  Future<void> _toggleBiometric(bool value) async {
    if (value) {
      // Enable biometric - verify first
      final authenticated =
          await _biometricService.authenticateBiometricOnly();
      if (authenticated) {
        await AuthPreferences.setBiometricEnabled(true);
        setState(() {
          _biometricEnabled = true;
        });
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Biometric login enabled'),
              backgroundColor: Colors.green,
            ),
          );
        }
      }
    } else {
      await AuthPreferences.setBiometricEnabled(false);
      setState(() {
        _biometricEnabled = false;
      });
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('Biometric login disabled'),
          ),
        );
      }
    }
  }

  Future<void> _logout() async {
    final shouldLogout = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Logout'),
        content: const Text('Are you sure you want to logout?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context, false),
            child: const Text('Cancel'),
          ),
          FilledButton(
            onPressed: () => Navigator.pop(context, true),
            child: const Text('Logout'),
          ),
        ],
      ),
    );

    if (shouldLogout == true) {
      // Keep biometric preference but clear auth status
      final biometricEnabled = await AuthPreferences.isBiometricEnabled();
      await AuthPreferences.setAuthenticated(false);
      // Restore biometric preference so it auto-triggers on next login
      if (biometricEnabled) {
        await AuthPreferences.setBiometricEnabled(true);
      }

      if (mounted) {
        Navigator.of(context).pushReplacement(
          MaterialPageRoute(builder: (_) => const LoginScreen()),
        );
      }
    }
  }

  Future<void> _fullLogout() async {
    final shouldLogout = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Full Logout'),
        content: const Text(
            'This will clear all saved data including biometric preferences. Continue?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context, false),
            child: const Text('Cancel'),
          ),
          FilledButton(
            style: FilledButton.styleFrom(backgroundColor: Colors.red),
            onPressed: () => Navigator.pop(context, true),
            child: const Text('Clear & Logout'),
          ),
        ],
      ),
    );

    if (shouldLogout == true) {
      await AuthPreferences.clearAll();

      if (mounted) {
        Navigator.of(context).pushReplacement(
          MaterialPageRoute(builder: (_) => const LoginScreen()),
        );
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Home'),
        actions: [
          IconButton(
            icon: const Icon(Icons.logout),
            onPressed: _logout,
            tooltip: 'Logout',
          ),
        ],
      ),
      body: Padding(
        padding: const EdgeInsets.all(24.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Card(
              child: Padding(
                padding: const EdgeInsets.all(24.0),
                child: Column(
                  children: [
                    CircleAvatar(
                      radius: 40,
                      backgroundColor:
                          Theme.of(context).colorScheme.primaryContainer,
                      child: Icon(
                        Icons.person,
                        size: 40,
                        color: Theme.of(context).colorScheme.primary,
                      ),
                    ),
                    const SizedBox(height: 16),
                    Text(
                      'Welcome, ${_username ?? 'User'}!',
                      style:
                          Theme.of(context).textTheme.headlineSmall?.copyWith(
                                fontWeight: FontWeight.bold,
                              ),
                    ),
                    const SizedBox(height: 8),
                    Text(
                      'You are successfully authenticated',
                      style: Theme.of(context).textTheme.bodyMedium?.copyWith(
                            color: Colors.grey,
                          ),
                    ),
                  ],
                ),
              ),
            ),
            const SizedBox(height: 24),

            // Security settings
            Text(
              'Security Settings',
              style: Theme.of(context).textTheme.titleMedium?.copyWith(
                    fontWeight: FontWeight.bold,
                  ),
            ),
            const SizedBox(height: 12),

            Card(
              child: Column(
                children: [
                  SwitchListTile(
                    title: const Text('Biometric Login'),
                    subtitle: Text(
                      _isBiometricAvailable
                          ? 'Use fingerprint or Face ID to login'
                          : 'Biometrics not available on this device',
                    ),
                    value: _biometricEnabled,
                    onChanged:
                        _isBiometricAvailable ? _toggleBiometric : null,
                    secondary: Icon(
                      _isBiometricAvailable
                          ? Icons.fingerprint
                          : Icons.fingerprint,
                      color: _isBiometricAvailable
                          ? Theme.of(context).colorScheme.primary
                          : Colors.grey,
                    ),
                  ),
                  const Divider(height: 1),
                  ListTile(
                    leading: const Icon(Icons.info_outline),
                    title: const Text('Authentication Status'),
                    subtitle: Text(
                      _biometricEnabled
                          ? 'Biometric login is active'
                          : 'Password login only',
                    ),
                    trailing: Icon(
                      _biometricEnabled
                          ? Icons.check_circle
                          : Icons.remove_circle_outline,
                      color: _biometricEnabled ? Colors.green : Colors.grey,
                    ),
                  ),
                ],
              ),
            ),

            const Spacer(),

            OutlinedButton.icon(
              onPressed: _logout,
              icon: const Icon(Icons.logout),
              label: const Text('Logout'),
              style: OutlinedButton.styleFrom(
                padding: const EdgeInsets.symmetric(vertical: 14),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(12),
                ),
              ),
            ),
            const SizedBox(height: 12),
            TextButton.icon(
              onPressed: _fullLogout,
              icon: const Icon(Icons.delete_forever, color: Colors.red),
              label: const Text(
                'Clear All Data & Logout',
                style: TextStyle(color: Colors.red),
              ),
            ),
          ],
        ),
      ),
    );
  }
